request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?originalId ?normalizedId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "3d0f07f9b84c4e31bbca562f472c8885") || 
         CONTAINS(LCASE(STR(?normalizedId)), "3d0f07f9b84c4e31bbca562f472c8885"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?startEvent ?endEvent ?task ?gateway WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL { ?startEvent a bboExt:StartEvent . ?startEvent tai:belongsTo ?choreo . }
  OPTIONAL { ?endEvent a bboExt:EndEvent . ?endEvent tai:belongsTo ?choreo . }
  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . }
  OPTIONAL { ?gateway a bboExt:ExclusiveGateway . ?gateway tai:belongsTo ?choreo . }
}
LIMIT 50
